<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  foreground</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span></span>
